def f(s):
    last = {}
    start = 0
    max_len = 0
    for i, ch in enumerate(s):
        if ch in last and last[ch] >= start:
            start = last[ch] + 1
        last[ch] = i
        max_len = max(max_len, i - start + 1)
    return max_len
